"use client";

import React, { createContext, useCallback, useEffect, useState } from "react";
import type { JettAuthClaims } from "../src/jwt";
import type { XUserProfile } from "../src/x-oauth";

export interface AuthState {
  isLoaded: boolean;
  isSignedIn: boolean;
  claims: JettAuthClaims | null;
  xProfile: XUserProfile | null;
  walletPubkey: string | null;
}

export interface AuthContextValue extends AuthState {
  signOut: () => Promise<void>;
  refreshSession: () => Promise<void>;
}

export const AuthContext = createContext<AuthContextValue>({
  isLoaded: false,
  isSignedIn: false,
  claims: null,
  xProfile: null,
  walletPubkey: null,
  signOut: async () => {},
  refreshSession: async () => {},
});

interface AuthProviderProps {
  children: React.ReactNode;
  sessionEndpoint?: string; // GET returns { claims, xProfile } or 401
  signOutEndpoint?: string; // POST to sign out
  refreshEndpoint?: string; // POST to refresh JWT
}

export function AuthProvider({
  children,
  sessionEndpoint = "/api/auth/session",
  signOutEndpoint = "/api/auth/signout",
  refreshEndpoint = "/api/auth/refresh",
}: AuthProviderProps) {
  const [state, setState] = useState<AuthState>({
    isLoaded: false,
    isSignedIn: false,
    claims: null,
    xProfile: null,
    walletPubkey: null,
  });

  const loadSession = useCallback(async () => {
    try {
      const res = await fetch(sessionEndpoint, { credentials: "include" });
      if (res.ok) {
        const data = await res.json();
        setState({
          isLoaded: true,
          isSignedIn: true,
          claims: data.claims,
          xProfile: data.xProfile ?? null,
          walletPubkey: data.claims?.sub?.replace("sol:", "") ?? null,
        });
      } else {
        setState((prev) => ({ ...prev, isLoaded: true, isSignedIn: false }));
      }
    } catch {
      setState((prev) => ({ ...prev, isLoaded: true, isSignedIn: false }));
    }
  }, [sessionEndpoint]);

  useEffect(() => {
    loadSession();
  }, [loadSession]);

  const signOut = useCallback(async () => {
    await fetch(signOutEndpoint, {
      method: "POST",
      credentials: "include",
    });
    setState({
      isLoaded: true,
      isSignedIn: false,
      claims: null,
      xProfile: null,
      walletPubkey: null,
    });
  }, [signOutEndpoint]);

  const refreshSession = useCallback(async () => {
    const res = await fetch(refreshEndpoint, {
      method: "POST",
      credentials: "include",
    });
    if (res.ok) {
      await loadSession();
    }
  }, [refreshEndpoint, loadSession]);

  return (
    <AuthContext.Provider
      value={{ ...state, signOut, refreshSession }}
    >
      {children}
    </AuthContext.Provider>
  );
}
