"use client";

import { useCallback, useState } from "react";

interface UseSolanaAuthOptions {
  challengeEndpoint?: string; // GET /api/auth/wallet/challenge?pubkey=X
  verifyEndpoint?: string; // POST /api/auth/wallet/verify
}

interface UseSolanaAuthReturn {
  connectAndSign: (signMessage: (message: Uint8Array) => Promise<Uint8Array>, publicKeyBase58: string) => Promise<boolean>;
  isAuthenticating: boolean;
  error: string | null;
}

export function useSolanaAuth(opts?: UseSolanaAuthOptions): UseSolanaAuthReturn {
  const [isAuthenticating, setIsAuthenticating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const challengeEndpoint = opts?.challengeEndpoint ?? "/api/auth/wallet/challenge";
  const verifyEndpoint = opts?.verifyEndpoint ?? "/api/auth/wallet/verify";

  const connectAndSign = useCallback(
    async (
      signMessage: (message: Uint8Array) => Promise<Uint8Array>,
      publicKeyBase58: string
    ): Promise<boolean> => {
      setIsAuthenticating(true);
      setError(null);

      try {
        // 1. Get nonce challenge from server
        const challengeRes = await fetch(
          `${challengeEndpoint}?pubkey=${publicKeyBase58}`
        );
        if (!challengeRes.ok) {
          throw new Error("Failed to get challenge");
        }
        const { message, nonce } = await challengeRes.json();

        // 2. Sign the message with wallet
        const messageBytes = new TextEncoder().encode(message);
        const signatureBytes = await signMessage(messageBytes);

        // 3. Send signature to server for verification + JWT issuance
        const verifyRes = await fetch(verifyEndpoint, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          credentials: "include",
          body: JSON.stringify({
            message,
            signature: uint8ArrayToBase64(signatureBytes),
            publicKey: publicKeyBase58,
            nonce,
          }),
        });

        if (!verifyRes.ok) {
          const err = await verifyRes.json();
          throw new Error(err.error ?? "Verification failed");
        }

        setIsAuthenticating(false);
        return true;
      } catch (e) {
        setError(e instanceof Error ? e.message : "Authentication failed");
        setIsAuthenticating(false);
        return false;
      }
    },
    [challengeEndpoint, verifyEndpoint]
  );

  return { connectAndSign, isAuthenticating, error };
}

function uint8ArrayToBase64(bytes: Uint8Array): string {
  let binary = "";
  for (let i = 0; i < bytes.length; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}
