"use client";

import { useCallback, useState } from "react";

interface UseXOAuthOptions {
  authEndpoint?: string; // GET /api/auth/x -> redirects to X
}

interface UseXOAuthReturn {
  initiateXLogin: () => void;
  isRedirecting: boolean;
}

export function useXOAuth(opts?: UseXOAuthOptions): UseXOAuthReturn {
  const [isRedirecting, setIsRedirecting] = useState(false);
  const endpoint = opts?.authEndpoint ?? "/api/auth/x";

  const initiateXLogin = useCallback(() => {
    setIsRedirecting(true);
    // Server-side route handles PKCE generation + redirect to X
    window.location.href = endpoint;
  }, [endpoint]);

  return { initiateXLogin, isRedirecting };
}
